const email = $input.item.json;
const subject = email.subject || '(No Subject)';
const body = (email.text || email.snippet || '').substring(0, 2000).replace(/<[^>]*>/g, '').trim();
const sender = email.from || email.sender || 'user@example.com';
const messageId = email.id || email.messageId || '';
const threadId = email.threadId || '';
return {
  subject,
  body,
  sender,
  messageId,
  threadId,
  preview: body.substring(0, 200)
};

const raw = $input.item.json.message.content.replace(/```json|```/g, '').trim();
const analysis = JSON.parse(raw);
const emailData = $('Extract & Clean Email').item.json;
return {
  ...analysis,
  subject: emailData.subject,
  body: emailData.body,
  sender: emailData.sender,
  messageId: emailData.messageId,
  threadId: emailData.threadId
};

const replyBody = $input.item.json.message.content;
const analysis = $('Parse Analysis').item.json;
return {
  reply_body: replyBody,
  reply_subject: 'Re: ' + analysis.subject,
  sender: analysis.sender,
  category: analysis.category,
  sentiment: analysis.sentiment,
  priority: analysis.priority,
  requires_human: analysis.requires_human,
  intent: analysis.intent,
  messageId: analysis.messageId,
  threadId: analysis.threadId,
  needs_escalation: analysis.sentiment === 'Urgent' || analysis.sentiment === 'Negative' || analysis.requires_human === true || analysis.priority === 'Critical'
};
